  it('BUG: orphan children are lost when parent is truncated', () => {
    // This test demonstrates the orphan children bug
    const mockSummary = {
      path: '/very/long/path/to/deeply/nested/directory/structure/test-budget.md',
      title: 'A Long Document Title That Uses Many Tokens',
      originalTokens: 1000,
      summaryTokens: 500,
