/**
 * Formatting functions for summarization output
 *
 * Responsible for converting summary data structures into human-readable text
 */

import { countTokensApprox } from '../utils/tokens.js'
import type {
  AssembledContext,
  DocumentSummary,
  SectionSummary,
} from './summarizer.js'

export interface FormatSummaryOptions {
  /** Maximum tokens for formatted output. If exceeded, sections will be truncated. */
  readonly maxTokens?: number
}

/**
 * Format a document summary for display
 *
 * Outputs a markdown-formatted summary with:
 * - Title and path
 * - Accurate token count (of the formatted output)
 * - Key topics
 * - Hierarchical section summaries
 */
export const formatSummary = (
  summary: DocumentSummary,
  options: FormatSummaryOptions = {},
): string => {
  const maxTokens = options.maxTokens

  // Flatten sections in order for incremental building
  const flatSections: { section: SectionSummary; depth: number }[] = []

  const collectSections = (section: SectionSummary, depth: number = 0) => {
    flatSections.push({ section, depth })
    for (const child of section.children) {
      collectSections(child, depth + 1)
    }
  }

  for (const section of summary.sections) {
    collectSections(section)
  }

  // Build static header parts (title, path, topics)
  const staticHeaderLines: string[] = []
  staticHeaderLines.push(`# ${summary.title}`)
  staticHeaderLines.push(`Path: ${summary.path}`)

  // Pre-calculate the token line with max reasonable values to estimate overhead
  // Use 9999 as placeholder for token count (4 digits is typical max)
  const tokenLineTemplate = `Tokens: 9999 (${(summary.compressionRatio * 100).toFixed(0)}% reduction from ${summary.originalTokens})`
  staticHeaderLines.push(tokenLineTemplate)

  // Truncation warning template (worst case)
  const truncationWarningTemplate = `⚠️ TRUNCATED: 999 sections omitted to fit token budget`

  // Topics line
  const topicsLine =
    summary.keyTopics.length > 0
      ? `**Topics:** ${summary.keyTopics.join(', ')}`
      : ''

  // Calculate fixed overhead: header + possible truncation + topics + newlines
  // This is the "chrome" around the content that we must reserve space for
  const fixedHeaderText = staticHeaderLines.join('\n')
  const fixedOverhead =
    countTokensApprox(fixedHeaderText) +
    countTokensApprox(truncationWarningTemplate) +
    (topicsLine ? countTokensApprox(topicsLine) : 0) +
    5 // Extra buffer for newlines between sections

  // Calculate available budget for section content
  const contentBudget =
    maxTokens !== undefined ? maxTokens - fixedOverhead : Infinity

  // Build sections, tracking tokens used
  const sectionLines: string[] = []
  let truncated = false
  let truncatedCount = 0
  let sectionTokensUsed = 0

  for (const { section, depth } of flatSections) {
    const indent = '  '.repeat(depth)
    const prefix = '#'.repeat(section.level)

    const newLines: string[] = []
    newLines.push(`${indent}${prefix} ${section.heading}`)
    if (section.summary) {
      newLines.push(`${indent}${section.summary}`)
    }

    const newContent = newLines.join('\n')
    const newTokens = countTokensApprox(newContent)

    // Check if adding this section would exceed budget
    if (maxTokens !== undefined) {
      if (sectionTokensUsed + newTokens > contentBudget) {
        truncated = true
        truncatedCount++
        continue // Skip this section
      }
    }

    sectionLines.push(...newLines)
    sectionTokensUsed += newTokens
  }

  // Build final output and calculate actual token count
  const sectionText = sectionLines.join('\n')

  // Construct final output
  const lines: string[] = []
  lines.push(`# ${summary.title}`)
  lines.push(`Path: ${summary.path}`)
  // Token line placeholder - will be filled in below
  const tokenLineIndex = lines.length
  lines.push('') // Placeholder

  // Show truncation warning if needed
  const showTruncation = truncated || (summary.truncated && summary.truncatedCount)
  if (showTruncation) {
    const totalTruncated = truncatedCount + (summary.truncatedCount ?? 0)
    lines.push(
      `⚠️ TRUNCATED: ${totalTruncated} sections omitted to fit token budget`,
    )
  }
  lines.push('')

  if (summary.keyTopics.length > 0) {
    lines.push(`**Topics:** ${summary.keyTopics.join(', ')}`)
    lines.push('')
  }

  lines.push(sectionText)

  // Calculate actual final token count
  const outputWithoutTokenLine = lines.join('\n')
  // Estimate token line contribution (it adds ~15-25 tokens typically)
  const tokenLineEstimate = countTokensApprox(tokenLineTemplate)
  const totalEstimate =
    countTokensApprox(outputWithoutTokenLine) + tokenLineEstimate

  // Now fill in the actual token line
  const actualTokenLine = `Tokens: ${totalEstimate} (${(summary.compressionRatio * 100).toFixed(0)}% reduction from ${summary.originalTokens})`
  lines[tokenLineIndex] = actualTokenLine

  return lines.join('\n')
}

/**
 * Format assembled context for display
 *
 * Outputs a combined view of multiple document summaries with:
 * - Header showing total tokens and source count
 * - Individual source summaries separated by dividers
 * - Overflow list for sources that didn't fit the budget
 */
export const formatAssembledContext = (context: AssembledContext): string => {
  const lines: string[] = []

  lines.push('# Context Assembly')
  lines.push(`Total tokens: ${context.totalTokens}/${context.budget}`)
  lines.push(`Sources: ${context.sources.length}`)
  lines.push('')

  for (const source of context.sources) {
    lines.push('---')
    lines.push('')
    lines.push(source.content)
  }

  if (context.overflow.length > 0) {
    lines.push('---')
    lines.push('')
    lines.push('## Overflow (not included due to budget)')
    for (const overflowPath of context.overflow) {
      lines.push(`- ${overflowPath}`)
    }
  }

  return lines.join('\n')
}

