const { countTokensApprox } = require('./dist/index.js');

// Test various text types
const tests = [
  { name: 'simple prose', text: 'Hello world, this is a test sentence.' },
  { name: 'code block', text: '\`\`\`javascript\nfunction foo() {\n  return bar;\n}\n\`\`\`' },
  { name: 'mixed content', text: '# Header\n\nSome prose here.\n\n\`\`\`js\nconst x = 1;\n\`\`\`\n\nMore text.' },
  { name: 'long path', text: '/very/long/path/to/deeply/nested/directory/structure/file.md' },
  { name: 'punctuation', text: 'Hello! What\\'s up? Fine, thanks. (I\\'m great!) @#\$%^&*()' },
  { name: 'inline code', text: 'Use \`const x = 1\` to declare a variable.' },
  { name: 'real doc', text: '# Test Document\\n\\nThis is a paragraph with some **bold** text and \`code\`.\\n\\n## Section\\n\\nMore content here.' },
];

async function compare() {
  const { get_encoding } = await import('tiktoken');
  const encoder = get_encoding('cl100k_base');

  console.log('Text Type     | Approx | Actual | Error%');
  console.log('--------------|--------|--------|-------');

  let totalError = 0;
  for (const { name, text } of tests) {
    const approx = countTokensApprox(text);
    const actual = encoder.encode(text).length;
    const errorPct = ((approx - actual) / actual * 100);
    const sign = errorPct >= 0 ? '+' : '';
    console.log(\`\${name.padEnd(14)}| \${String(approx).padEnd(6)} | \${String(actual).padEnd(6)} | \${sign}\${errorPct.toFixed(1)}%\`);
    totalError += Math.abs(errorPct);
  }
  console.log('\\nAverage absolute error:', (totalError / tests.length).toFixed(1) + '%');

  encoder.free();
}

compare().catch(console.error);
"

